//! Mesh-governed depth field: classical + topology priors fused with per-pixel confidence and
//! serde provenance (`mesh_depth_provenance/v1`). Optional ONNX third prior when `depth-onnx` is enabled.
//! Optional **five-level monocular cue** stack ([`crate::depth_monocular_cues`]) blends Gibsonian
//! proxies when [`MeshDepthConfig::monocular_cue_blend`] is set. For **metres**, pass
//! [`MeshDepthMetricAnchor`] as the sixth argument to [`build_mesh_depth_field`], or call
//! [`crate::depth_metric_anchor`] helpers on a ratio-scale field alone.

use serde::{Deserialize, Serialize};

use crate::depth_extrusion::{estimate_depth_classical_normalized, DepthError, DepthEstimator};
use crate::depth_metric_anchor::scale_relative_to_meters;
pub use crate::depth_metric_anchor::{
    FnMeshDepthMetricAnchor, KnownExtentMaskMetricAnchor, MeshDepthMetricAnchor, MetricAnchorFire,
};
use crate::depth_monocular_cues::{build_monocular_cue_maps, MonocularCueProvenance};
use crate::topology_mask::{
    build_topology_alpha, RgbLayout, TopologyAlphaConfig, TopologyMaskProvenance,
};

/// JSON `schema_version` for [`MeshDepthProvenance`].
pub const MESH_DEPTH_PROVENANCE_VERSION: &str = "mesh_depth_provenance/v1";

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq, Eq, Hash)]
#[serde(rename_all = "snake_case")]
pub enum DepthPriorId {
    Classical,
    TopologyAlpha,
    Onnx,
    /// Five-level dyadic luma bands + Gibsonian cue proxies (see `depth_monocular_cues`).
    MonocularCues,
    /// Metric / known-size anchor (see [`crate::depth_metric_anchor::MeshDepthMetricAnchor`]).
    MetricAnchor,
}

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq)]
pub struct DepthFragmentReport {
    pub prior: DepthPriorId,
    /// Scalar summary for logging (e.g. mean depth response).
    pub mean_response: f32,
    pub admissible: bool,
}

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq)]
pub struct MeshDepthProvenance {
    pub schema_version: String,
    pub width: u32,
    pub height: u32,
    pub degraded_mode: String,
    pub topology: TopologyMaskProvenance,
    pub fragments: Vec<DepthFragmentReport>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub monocular_cues: Option<MonocularCueProvenance>,
    /// Which metric anchor ran (or failed); [`MeshDepthField::values_meters`] is populated when scale is known.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub metric_anchor: Option<MetricAnchorFire>,
}

#[derive(Clone, Debug)]
pub struct MeshDepthField {
    /// Ratio-scale admitted depth in `[0,1]` (unchanged by metric anchors; use for extrusion).
    pub values: Vec<f32>,
    pub confidence: Vec<f32>,
    /// When a [`MeshDepthMetricAnchor`] succeeds: `values * meters_per_relative_unit` (metres).
    pub values_meters: Option<Vec<f32>>,
}

#[derive(Clone, Debug)]
pub struct MeshDepthConfig {
    pub topology: TopologyAlphaConfig,
    /// When ONNX prior present: if `|d_classical - d_onnx|` exceeds this, confidence is reduced.
    pub agreement_threshold: f32,
    /// Blend target when topology alpha is low.
    pub neutral_depth: f32,
    /// Blend Gibsonian / five-level cue plane into admitted depth (`0` = off, preserves legacy behavior).
    pub monocular_cue_blend: f32,
}

impl Default for MeshDepthConfig {
    fn default() -> Self {
        Self {
            topology: TopologyAlphaConfig::default(),
            agreement_threshold: 0.22,
            neutral_depth: 0.5,
            monocular_cue_blend: 0.0,
        }
    }
}

/// Fuse classical depth + topology alpha; optionally third prior from `onnx` estimator;
/// optional [`MeshDepthMetricAnchor`] records **which** metric anchor fired on [`MeshDepthProvenance::metric_anchor`]
/// and fills [`MeshDepthField::values_meters`] without silently replacing [`MeshDepthField::values`].
pub fn build_mesh_depth_field(
    rgb_f32_unit: &[f32],
    width: u32,
    height: u32,
    config: &MeshDepthConfig,
    onnx: Option<&mut dyn DepthEstimator>,
    metric_anchor: Option<&mut dyn MeshDepthMetricAnchor>,
) -> Result<(MeshDepthField, MeshDepthProvenance), DepthError> {
    if width == 0 || height == 0 {
        return Err(DepthError::Shape);
    }
    let w = width as usize;
    let h = height as usize;
    let n = w * h;

    let classical = estimate_depth_classical_normalized(rgb_f32_unit, w, h)?;
    let (alpha, topo_prov) = build_topology_alpha(
        rgb_f32_unit,
        width,
        height,
        RgbLayout::SequentialRgb,
        &config.topology,
    )
    .map_err(DepthError::Mesh)?;

    if alpha.len() != n {
        return Err(DepthError::Shape);
    }

    let mut onnx_depth: Option<Vec<f32>> = None;
    let mut degraded = "full".to_string();
    if let Some(est) = onnx {
        match est.estimate_normalized(rgb_f32_unit, w, h) {
            Ok(v) if v.len() == n => {
                onnx_depth = Some(v);
            }
            Ok(_) => {
                degraded = "onnx_shape_mismatch".into();
            }
            Err(DepthError::OnnxDisabled) => {
                degraded = "onnx_disabled".into();
            }
            Err(e) => {
                degraded = format!("onnx_err_{}", e);
            }
        }
    }

    let cue_blend = config.monocular_cue_blend.clamp(0.0, 1.0);
    let mut cue_prior: Option<Vec<f32>> = None;
    let mut cue_summary: Option<MonocularCueProvenance> = None;
    if cue_blend > 1e-6 {
        let maps = build_monocular_cue_maps(rgb_f32_unit, w, h)?;
        cue_summary = Some(maps.provenance);
        cue_prior = Some(maps.cue_prior);
    }

    let mut values = vec![0.0_f32; n];
    let mut confidence = vec![0.0_f32; n];

    let mean_c: f32 = classical.iter().sum::<f32>() / n.max(1) as f32;
    let mut frag = vec![
        DepthFragmentReport {
            prior: DepthPriorId::Classical,
            mean_response: mean_c,
            admissible: true,
        },
        DepthFragmentReport {
            prior: DepthPriorId::TopologyAlpha,
            mean_response: alpha.iter().sum::<f32>() / n.max(1) as f32,
            admissible: topo_prov.scales.iter().all(|s| s.admissible),
        },
    ];

    if let Some(ref od) = onnx_depth {
        let mean_o = od.iter().sum::<f32>() / n.max(1) as f32;
        frag.push(DepthFragmentReport {
            prior: DepthPriorId::Onnx,
            mean_response: mean_o,
            admissible: degraded == "full",
        });
    }

    if let Some(ref cp) = cue_prior {
        let mean_q: f32 = cp.iter().copied().sum::<f32>() / n.max(1) as f32;
        frag.push(DepthFragmentReport {
            prior: DepthPriorId::MonocularCues,
            mean_response: mean_q,
            admissible: true,
        });
    }

    let thr = config.agreement_threshold.max(1e-6);
    let neutral = config.neutral_depth.clamp(0.0, 1.0);

    for i in 0..n {
        let a = alpha[i].clamp(0.0, 1.0);
        let dc = classical[i].clamp(0.0, 1.0);
        let base = if let Some(ref od) = onnx_depth {
            let do_ = od[i].clamp(0.0, 1.0);
            let disagree = (dc - do_).abs();
            let agree = (1.0 - (disagree / thr).min(1.0)) * a;
            let fused = 0.5 * (dc + do_);
            (fused * a + neutral * (1.0 - a), agree)
        } else {
            (dc * a + neutral * (1.0 - a), a)
        };
        let mut val = base.0.clamp(0.0, 1.0);
        let mut conf = base.1.clamp(0.0, 1.0);
        if let Some(ref cp) = cue_prior {
            let cue = cp[i].clamp(0.0, 1.0);
            let align = (1.0 - (dc - cue).abs()).clamp(0.0, 1.0);
            let mixed = val * 0.62 + cue * 0.38;
            val = (val * (1.0 - cue_blend) + mixed * cue_blend).clamp(0.0, 1.0);
            conf = (conf * (1.0 - 0.35 * cue_blend * (1.0 - align))).clamp(0.0, 1.0);
        }
        values[i] = val;
        confidence[i] = conf;
    }

    let mut values_meters: Option<Vec<f32>> = None;
    let mut metric_anchor_fire: Option<MetricAnchorFire> = None;
    if let Some(anchor) = metric_anchor {
        match anchor.resolve_metric_scale(rgb_f32_unit, w, h, &values) {
            Ok(fire) => {
                metric_anchor_fire = Some(fire.clone());
                if let Some(k) = fire.meters_per_relative_unit() {
                    values_meters = Some(scale_relative_to_meters(&values, k));
                    frag.push(DepthFragmentReport {
                        prior: DepthPriorId::MetricAnchor,
                        mean_response: k,
                        admissible: true,
                    });
                } else {
                    frag.push(DepthFragmentReport {
                        prior: DepthPriorId::MetricAnchor,
                        mean_response: 0.0,
                        admissible: false,
                    });
                }
            }
            Err(e) => {
                let fail = MetricAnchorFire::Failed {
                    message: e.to_string(),
                };
                metric_anchor_fire = Some(fail);
                frag.push(DepthFragmentReport {
                    prior: DepthPriorId::MetricAnchor,
                    mean_response: 0.0,
                    admissible: false,
                });
            }
        }
    }

    let prov = MeshDepthProvenance {
        schema_version: MESH_DEPTH_PROVENANCE_VERSION.to_string(),
        width,
        height,
        degraded_mode: degraded,
        topology: topo_prov,
        fragments: frag,
        monocular_cues: cue_summary,
        metric_anchor: metric_anchor_fire,
    };

    Ok((
        MeshDepthField {
            values,
            confidence,
            values_meters,
        },
        prov,
    ))
}

/// Admitted per-pixel depth as a heightfield buffer for [`crate::depth_extrusion::extrude_depth_heightfield_rgb`].
#[inline]
pub fn mesh_depth_to_heightfield(field: &MeshDepthField) -> Vec<f32> {
    field.values.clone()
}

/// Metre-scale depth when [`MeshDepthField::values_meters`] was filled by a successful anchor.
#[inline]
pub fn mesh_depth_meters_slice(field: &MeshDepthField) -> Option<&[f32]> {
    field.values_meters.as_deref()
}

/// Tile-level summaries for logging / Forge: mirrors `PleromaticFrame`-style keys (`level`, `phase`, `media`)
/// without routing full-resolution tensors through the holographic voxel sieve.
#[derive(Clone, Debug, Serialize, Deserialize, PartialEq)]
pub struct PleromaticDepthTileSummary {
    /// Closure / dyadic scale index (provenance-first; not necessarily `SovereignSieve` voxel level).
    pub level: u32,
    /// Triton-3 phase bucket `level % 3` (see `open-source/gnosis/distributed-inference-host/src/pleromatic-monster-mesh.ts`).
    pub phase: u8,
    pub media: String,
    pub tile_x: u32,
    pub tile_y: u32,
    pub mean_depth: f32,
    pub mean_confidence: f32,
}

/// Mean depth and confidence per `tile_px × tile_px` tile (partial tail tiles included). `tile_px` must be ≥ 1.
pub fn build_mesh_depth_tile_summaries(
    field: &MeshDepthField,
    width: u32,
    height: u32,
    tile_px: u32,
    level: u32,
) -> Result<Vec<PleromaticDepthTileSummary>, DepthError> {
    if width == 0 || height == 0 || tile_px == 0 {
        return Err(DepthError::Shape);
    }
    let w = width as usize;
    let h = height as usize;
    let n = w * h;
    if field.values.len() != n || field.confidence.len() != n {
        return Err(DepthError::Shape);
    }
    let tw = tile_px as usize;
    let phase = (level % 3) as u8;
    let mut out = Vec::new();
    let mut ty = 0_u32;
    while (ty as usize) * tw < h {
        let mut tx = 0_u32;
        while (tx as usize) * tw < w {
            let x0 = (tx as usize) * tw;
            let y0 = (ty as usize) * tw;
            let x1 = (x0 + tw).min(w);
            let y1 = (y0 + tw).min(h);
            let mut sum_d = 0.0_f32;
            let mut sum_c = 0.0_f32;
            let mut cnt = 0_usize;
            for yy in y0..y1 {
                for xx in x0..x1 {
                    let i = yy * w + xx;
                    sum_d += field.values[i];
                    sum_c += field.confidence[i];
                    cnt += 1;
                }
            }
            let fc = cnt as f32;
            out.push(PleromaticDepthTileSummary {
                level,
                phase,
                media: "Image".to_string(),
                tile_x: tx,
                tile_y: ty,
                mean_depth: sum_d / fc,
                mean_confidence: sum_c / fc,
            });
            tx += 1;
        }
        ty += 1;
    }
    Ok(out)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::depth_extrusion::DepthEstimator;

    struct ConstantDepthPrior {
        depth: Vec<f32>,
    }

    impl DepthEstimator for ConstantDepthPrior {
        fn estimate_normalized(
            &mut self,
            rgb_f32_unit: &[f32],
            width: usize,
            height: usize,
        ) -> Result<Vec<f32>, DepthError> {
            let n = width * height;
            let need = n * 3;
            if rgb_f32_unit.len() != need || self.depth.len() != n {
                return Err(DepthError::Shape);
            }
            Ok(self.depth.clone())
        }
    }

    #[test]
    fn mesh_depth_bootstrap_two_fragments() {
        let w = 8_u32;
        let h = 8_u32;
        let mut rgb = vec![0.0_f32; (w * h * 3) as usize];
        for i in 0..(w * h) as usize {
            rgb[i * 3] = 0.2;
            rgb[i * 3 + 1] = 0.4;
            rgb[i * 3 + 2] = 0.7;
        }
        let (field, prov) =
            build_mesh_depth_field(&rgb, w, h, &MeshDepthConfig::default(), None, None).unwrap();
        assert_eq!(field.values.len(), (w * h) as usize);
        assert_eq!(field.confidence.len(), (w * h) as usize);
        assert_eq!(prov.schema_version, MESH_DEPTH_PROVENANCE_VERSION);
        assert_eq!(prov.fragments.len(), 2);
        assert!(field.values.iter().all(|&x| x >= 0.0 && x <= 1.0));
        assert!(field.confidence.iter().all(|&x| x >= 0.0 && x <= 1.0));
    }

    #[test]
    fn stub_onnx_disagreement_lowers_mean_confidence() {
        let w = 16_u32;
        let h = 16_u32;
        let n = (w * h) as usize;
        let mut rgb = vec![0.45_f32; n * 3];
        // High-contrast patch so classical proxy differs strongly from flat "onnx" prior.
        for i in 0..n {
            let x = i % w as usize;
            if x < 4 {
                rgb[i * 3] = 0.05;
                rgb[i * 3 + 1] = 0.95;
                rgb[i * 3 + 2] = 0.1;
            }
        }
        let (field_base, _) =
            build_mesh_depth_field(&rgb, w, h, &MeshDepthConfig::default(), None, None).unwrap();
        let mean_conf_base: f32 = field_base.confidence.iter().copied().sum::<f32>() / n as f32;

        let mut stub = ConstantDepthPrior {
            depth: vec![0.02_f32; n],
        };
        let (field_fused, prov) = build_mesh_depth_field(
            &rgb,
            w,
            h,
            &MeshDepthConfig::default(),
            Some(&mut stub),
            None,
        )
        .unwrap();
        assert_eq!(prov.fragments.len(), 3);
        let mean_conf_fused: f32 = field_fused.confidence.iter().copied().sum::<f32>() / n as f32;
        assert!(
            mean_conf_fused < mean_conf_base,
            "expected lower mean sieve confidence when stub ONNX disagrees with classical; base={} fused={}",
            mean_conf_base,
            mean_conf_fused
        );

        let tiles = build_mesh_depth_tile_summaries(&field_fused, w, h, 8, 2).unwrap();
        assert!(!tiles.is_empty());
        assert!(tiles.iter().all(|t| t.media == "Image"));
        assert!(tiles.iter().all(|t| t.phase == 2 % 3));
        let hf = mesh_depth_to_heightfield(&field_fused);
        assert_eq!(hf.len(), n);
    }

    #[test]
    fn monocular_cue_blend_adds_fragment_and_provenance() {
        let w = 12_u32;
        let h = 12_u32;
        let n = (w * h) as usize;
        let rgb: Vec<f32> = (0..n * 3)
            .map(|i| ((i % 17) as f32 * 0.02).clamp(0.0, 1.0))
            .collect();
        let mut cfg = MeshDepthConfig::default();
        cfg.monocular_cue_blend = 0.2;
        let (field, prov) = build_mesh_depth_field(&rgb, w, h, &cfg, None, None).unwrap();
        assert_eq!(prov.fragments.len(), 3);
        assert!(prov
            .fragments
            .iter()
            .any(|f| f.prior == DepthPriorId::MonocularCues));
        assert!(prov.monocular_cues.is_some());
        assert_eq!(field.values.len(), n);
    }

    #[test]
    fn metric_anchor_known_extent_records_fire_and_parallel_meters() {
        let w = 16_u32;
        let h = 16_u32;
        let n = (w * h) as usize;
        let mut rgb = vec![0.0_f32; n * 3];
        for i in 0..n {
            rgb[i * 3] = (i % 7) as f32 * 0.1;
            rgb[i * 3 + 1] = 0.35;
            rgb[i * 3 + 2] = 0.55;
        }
        let mask = vec![1.0_f32; n];
        let mut anchor = KnownExtentMaskMetricAnchor {
            mask,
            physical_extent_m: 2.1,
        };
        let (field, prov) = build_mesh_depth_field(
            &rgb,
            w,
            h,
            &MeshDepthConfig::default(),
            None,
            Some(&mut anchor),
        )
        .unwrap();
        assert!(matches!(
            prov.metric_anchor,
            Some(MetricAnchorFire::KnownExtentMask { .. })
        ));
        let vm = field.values_meters.as_ref().expect("meters buffer");
        assert_eq!(vm.len(), n);
        assert!(prov
            .fragments
            .iter()
            .any(|f| f.prior == DepthPriorId::MetricAnchor && f.admissible));
        assert!(mesh_depth_meters_slice(&field).is_some());
        assert!(field.values.iter().all(|&x| x >= 0.0 && x <= 1.0));
    }
}
